import React, { useEffect } from 'react';
import './DarkTheme.css';
import Prism from 'prismjs';
import { MainContent } from './styles';
import useMobile from '../../../helpers/hooks/useMobile';
import useTablet from '../../../helpers/hooks/useTablet';

const DarkContent = ({ contents }) => {
    const isMobile = useMobile();
    const isTablet = useTablet();

    useEffect(()=> {
        Prism.highlightAll();
    },[])

    return (
        <MainContent isMobile={isMobile} isTablet={isTablet} className='dark'  dangerouslySetInnerHTML={{__html: contents}}/>
    );
};

export default DarkContent;
