import React, { useContext } from 'react';
import * as Styled from './styles';
import { DarkSubTitle } from '../../../styles/common';
import Button from '../../../components/Button';
import { useInView } from 'react-intersection-observer';
import { useNavigate } from 'react-router-dom';
import useMobile from '../../../helpers/hooks/useMobile';
import { ThemeContext } from 'styled-components';
import useTablet from '../../../helpers/hooks/useTablet';

const CTASection = ({currentPost}) => {
    const { ref, inView } = useInView({
		threshold: 0,
		triggerOnce: true,
	});
    const {isBright} = useContext(ThemeContext);
    const navigate = useNavigate();
    const isMobile = useMobile();
    const isTablet = useTablet();

    return (
        <Styled.CTASectionContainer ref={ref} isTablet={isTablet} inView={inView} isMobile={isMobile} isBright={isBright}>
            <Styled.CTASection isfooter={!currentPost.linkedPostsId && isMobile}>
                <DarkSubTitle>Have an idea for a project?</DarkSubTitle>
                <Styled.Desctiption>Get a consultation from our lead specealists</Styled.Desctiption>
                <Styled.ButtonContainer>
                    <Button colorReverse={isBright ? false : true} onClick={() => navigate('/home')}>
                        Send us a request
                    </Button>
                </Styled.ButtonContainer>
            </Styled.CTASection>
        </Styled.CTASectionContainer>
    );
};

export default CTASection;