import React, { useContext } from 'react';
import * as Styled from './styles';
import { useInView } from 'react-intersection-observer';
import categories from '../../../constants/categoriesColors';
import { ThemeContext } from 'styled-components';
import useMobile from '../../../helpers/hooks/useMobile';
import JsonData from '../../posts/output.json'
import { useNavigate } from 'react-router-dom';
import useTablet from '../../../helpers/hooks/useTablet';

const ReadAlsoSection = ({currentPost}) => {
    const { ref, inView } = useInView({
		threshold: 0,
		triggerOnce: true,
	});
    const {isBright} = useContext(ThemeContext);
    const isMobile = useMobile();
    const isTablet = useTablet();
    const {data} = JsonData;
    const navigate = useNavigate();

    return (
        <Styled.ReadAlsoSection ref={ref} inView={inView}>
            <Styled.ReadAlsoContainer isTablet={isTablet} isMobile={isMobile} isBright={isBright}>
                <Styled.ReadAlsoTitle>Read Also</Styled.ReadAlsoTitle>
                <Styled.ReadAlsoCards>
                    {currentPost.linkedPostsId.map(item => {
                        const post = data.find(post => post.id === item);
                        return (
                            <Styled.ReadAlsoCard key={item} onClick={() => navigate('/blog/' + item)}>
                                <Styled.CardImageContainer>
                                    <Styled.CardImage src={post.previewImage}/>
                                </Styled.CardImageContainer>
                                <Styled.CardCategory
                                color={isBright ? categories[post.category].bright : categories[post.category].dark}
                                >{post.category}</Styled.CardCategory>
                                <Styled.CardTitle>{post.title}</Styled.CardTitle>
                                <Styled.CardAuthor>{post.author}</Styled.CardAuthor>
                            </Styled.ReadAlsoCard>
                        )
                    })}
                </Styled.ReadAlsoCards>
            </Styled.ReadAlsoContainer>
        </Styled.ReadAlsoSection>
    );
};

export default ReadAlsoSection;