import React, { useContext, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import JsonData from '../../posts/output.json';
import * as Styled from './styles';
import DarkContent from '../../components/DarkContent';
import BrightContent from '../../components/BrightContent';
import { ThemeContext } from 'styled-components';
import useMobile from '../../../helpers/hooks/useMobile';
import dataFormatString from '../../../helpers/functions/dataFormatString';
import dataTimeFormat from '../../../helpers/functions/dataTimeFormat';
import categories from '../../../constants/categoriesColors';
import ReadAlsoSection from '../../components/ReadAlsoSection';
import CTASection from '../../components/CTASection';
import useTablet from '../../../helpers/hooks/useTablet';
import setLoaderStatus from '../../../helpers/functions/setLoaderStatus';
import { Helmet } from 'react-helmet';

const BlogPage = () => {
    const {isBright} = useContext(ThemeContext);
    const isMobile = useMobile();
    const isTablet = useTablet();
    const {id} = useParams();
    const navigate = useNavigate();
    const {data} = JsonData;
    const currentPost = data.find(item => item.id === id);
    const createdData =  currentPost.createdAt;

    useEffect(()=>{
        window.scrollTo(0, 0);
        setLoaderStatus(true);
        
        return setLoaderStatus(false);
    },[id])

    return (
        <Styled.Layout isBright={isBright} isTablet={isTablet} isMobile={isMobile}>
            
                <Helmet>
                    <meta id='og-title' property='og:title' content={currentPost.title} />
                    <meta id='og-image' property='og:image' content={currentPost.previewImage} />
                    <meta id='site-name' property='og:url' content={`play.jito.dev/blog/${id}`} />
                    <meta id='description' property='og:description' content={currentPost.description}/>
                </Helmet>
           
            <Styled.BlogPageContainer>
                <Styled.Header>
                    <Styled.BackLink onClick={() => navigate('/blog')}>{'<'} Back to blog</Styled.BackLink>
                    <Styled.HeaderCategory
                      color={isBright ? categories[currentPost.category].bright : categories[currentPost.category].dark}
                    >
                        {currentPost.category}
                    </Styled.HeaderCategory>
                    <Styled.HeaderTitle>{currentPost.title}</Styled.HeaderTitle>
                    <Styled.HeaderAuthorBlock>
                        <cite>by {currentPost.author}</cite>
                        <time dateTime={dataTimeFormat(createdData)}>
                            {dataFormatString(createdData)}
                        </time>
                    </Styled.HeaderAuthorBlock>
                </Styled.Header>
                <Styled.HeaderImgParralax image={currentPost.previewImage}>
                    <Styled.HeaderImg src={currentPost.previewImage} alt='main blog' />
                </Styled.HeaderImgParralax>
                {isBright ? <BrightContent contents={currentPost.contents} /> : <DarkContent contents={currentPost.contents} />}
            </Styled.BlogPageContainer>
            <CTASection currentPost={currentPost}/>
            {currentPost.linkedPostsId && <ReadAlsoSection currentPost={currentPost}/>}
        </Styled.Layout>
    );
};

export default BlogPage;
