import styled from 'styled-components';
import diamonds from '../../../assets/images/diamonds.svg';
import arrow from '../../../assets/images/arrow.svg';
import doubleOptions from '../../../helpers/functions/doubleOptions';

export const MainContent = styled.div`
    display: flex;
    flex-direction: column;
    align-items: center;
    width: ${props => props.isTablet ? doubleOptions(props.isMobile,'calc(100% - 32px)','calc(100% - 96px)') : '976px'};
    font-family: 'POPPINS';
    font-weight: 400;
    font-size: ${props => props.isTablet ? doubleOptions(props.isMobile,'16px','20px') : '22px'};
    line-height: ${props => props.isTablet ? doubleOptions(props.isMobile,'32px','36px') : '40px'};
    margin-left: ${props => props.isMobile ? '16px' : '0'};
    gap: ${props => props.isMobile ? '16px' : '32px'};
    color: #FFFFFF;
    
    & > * {
        margin: 0;
    }

    & details {
        padding: ${props => props.isMobile ? '16px' : '24px'};
        border: 1px solid #46454F;
        border-radius: 4px;
        background-color: #02010F;

        & summary {
            padding-left: 30px;
            position: relative;
            font-size: ${props => props.isTablet ? '20px' : '24px'};
            line-height: ${props => props.isTablet ? '30px' : '36px'};
            cursor: pointer;
            font-weight: 500;

            &::before {
                content: '';
                position: absolute;
                background-image: url(${diamonds});
                height: 100%;
                width: 25px;
                background-position: center;
                background-repeat: no-repeat;
                left: -6px;
            }

            &::after {
                content: '';
                position: absolute;
                background-image: url(${arrow});
                height: 100%;
                width: 25px;
                background-position: center;
                background-repeat: no-repeat;
                right: -6px;
                transition: 0.2s;
            }
        }
    }

    & details[open] > summary {
        margin-bottom: 24px;
        &::after {
            transform: rotateX(180deg);
        }
    }
    
    & details summary::-webkit-details-marker,
    & details summary::marker {
     display: none; 
     content: '';
    }

    & iframe {
        width: 100%;
        height: 500px;
    }
    
    & .quote {
        padding-left: 24px;
        position: relative;

        &::before {
            content: '';
            position: absolute;
            width: 8px;
            height: 100%;
            background-color: #7DC6C4;
            left: 0;
        }
    }
    
    & p {
        width: 100%;

        & img {
            width: 100%;
        }
    }

    & img {
        width: 100%;
        height: auto;
    }

    & a {
        font-size: ${props => props.isTablet ? doubleOptions(props.isMobile,'16px','20px') : '22px'};
        line-height: ${props => props.isTablet ? doubleOptions(props.isMobile,'32px','36px') : '40px'};
        color: #7DC6C4;
        font-family: 'POPPINS';
        text-decoration-line: underline;
        &:hover {
            color: blue;
        }
    }

    & h3,h2,details {
        width: 100%;
        font-weight: 500;
    }

    & h2 {
        font-size: ${props => props.isMobile ? '24px' : '32px'};
        line-height: ${props => props.isMobile ? '32px' : '48px'};
        margin-top: ${props => props.isMobile ? '16px' : '32px'};
    }

    & h3 {
        font-size: ${props => props.isMobile ? '20px' : '28px'};
        line-height: ${props => props.isMobile ? '32px' : '40px'};
        margin-top: ${props => props.isMobile ? '16px' : '32px'};
    }

    & h4 {
        font-family: 'POPPINS';
        font-weight: 500;
        font-size: ${props => props.isMobile ? '20px' : '24px'};
        width: 100%
    }

    & ul {
        width: 100%;
        margin-top: 0;
        list-style: none;
        padding: 0;
    }

    & li {
        font-weight: 400;

        & a {
            font-family: 'POPPINS';
            font-weight: 400;
            font-size: ${props => props.isTablet ? doubleOptions(props.isMobile,'16px','20px') : '22px'};
            line-height: ${props => props.isTablet ? doubleOptions(props.isMobile,'32px','36px') : '40px'};
            color: #7DC6C4;
            &:hover {
                color: blue;
            }
        }
    }
`;